	@Test
	void saveQueryHandlesAccessibilityWriteFlagsAndRepositoryFallbacks() throws Exception {
		QueryServlet servlet = new QueryServlet();
		QueryStorage storage = mock(QueryStorage.class);
		HttpServletResponse response = mock(HttpServletResponse.class);
		StringWriter body = new StringWriter();
		WorkbenchRequest inaccessible = mockSaveRequest("first");
		WorkbenchRequest noOverwrite = mockSaveRequest("second");
		WorkbenchRequest savePrivate = mockSaveRequest("third");
		Repository repository = mock(Repository.class);
		RepositoryInfo info = new RepositoryInfo();

		when(repository.getValueFactory()).thenReturn(SimpleValueFactory.getInstance());
		when(response.getWriter()).thenReturn(new PrintWriter(body));
		when(storage.checkAccess(null)).thenReturn(false);
		when(storage.checkAccess(repository)).thenReturn(true);
		when(storage.askExists(expectedRepositoryReference("unknown-repository"), "first", "")).thenReturn(false);
		when(storage.askExists(expectedRepositoryReference(repository.getClass().getName()), "second", "bob"))
				.thenReturn(true);
		when(storage.askExists(expectedRepositoryReference("https://example.org/repositories/test"), "third", "carol"))
				.thenReturn(false);

		servlet.substituteQueryStorage(storage);

		assertThatCode(() -> servlet.doPost(inaccessible, response, "/transform")).doesNotThrowAnyException();
		assertThat(body.toString()).contains("\"accessible\":false");

		body.getBuffer().setLength(0);
		info.setLocation(null);
		servlet.setRepository(repository);
		servlet.setRepositoryInfo(info);
		assertThatCode(() -> servlet.doPost(noOverwrite, response, "/transform")).doesNotThrowAnyException();
		assertThat(body.toString()).contains("\"existed\":true").contains("\"written\":false");
		verify(storage, never()).updateQuery(any(), anyString(), eq(false), eq(QueryLanguage.SPARQL), anyString(),
				eq(false), eq(20), eq(0));
		verify(storage, never()).saveQuery(anyString(), eq("second"), eq("bob"), eq(false), eq(QueryLanguage.SPARQL),
				anyString(), eq(false), eq(20), eq(0));

		body.getBuffer().setLength(0);
		info.setLocation(new URL("https://example.org/repositories/test"));
		servlet.setRepositoryInfo(info);
		assertThatCode(() -> servlet.doPost(savePrivate, response, "/transform")).doesNotThrowAnyException();
		verify(storage).saveQuery(expectedRepositoryReference("https://example.org/repositories/test"), "third",
				"carol", false, QueryLanguage.SPARQL, SHORT_QUERY, false, 20, 0);
		assertThat(body.toString()).contains("\"accessible\":true").contains("\"written\":true");
	}

	private static RecordingQueryServlet newInitializedServlet() throws ServletException {
		try {
			shutdownDefaultQueryStorage();
		} catch (Exception e) {
			throw new ServletException(e);
		}
		RecordingQueryServlet servlet = new RecordingQueryServlet();
		servlet.setRepositoryManager(mock(RepositoryManager.class));
		servlet.init(TestServletConfig.withParams("query", "transformations", "/transform", "cookie-max-age", "60"));
		return servlet;
	}

	private static void shutdownDefaultQueryStorage() throws Exception {
		AppConfiguration appConfiguration = new AppConfiguration("Workbench", "RDF4J Workbench");
		appConfiguration.init(false);
		QueryStorage.getSingletonInstance(appConfiguration).shutdown();
	}

	private static WorkbenchRequest mockSaveRequest(String queryName) throws Exception {
		WorkbenchRequest request = mock(WorkbenchRequest.class);
		when(request.getParameter("action")).thenReturn("save");
		when(request.isParameterPresent(QueryServlet.QUERY)).thenReturn(true);
		when(request.getParameter(QueryServlet.QUERY)).thenReturn(SHORT_QUERY);
		when(request.getParameter("query-name")).thenReturn(queryName);
		when(request.getParameter("queryLn")).thenReturn("SPARQL");
		when(request.getParameter("limit_query")).thenReturn("20");
		when(request.getInt("query-timeout")).thenReturn(0);
		when(request.getParameter("query-timeout")).thenReturn("0");
		when(request.isParameterPresent("infer")).thenReturn(false);
		if ("first".equals(queryName)) {
			when(request.getParameter("overwrite")).thenReturn("false");
			when(request.getParameter("save-private")).thenReturn("false");
			when(request.getParameter("server-user")).thenReturn(null);
		} else if ("second".equals(queryName)) {
			when(request.getParameter("overwrite")).thenReturn("false");
			when(request.getParameter("save-private")).thenReturn("true");
			when(request.getParameter("server-user")).thenReturn("bob");
		} else {
			when(request.getParameter("overwrite")).thenReturn("false");
			when(request.getParameter("save-private")).thenReturn("true");
			when(request.getParameter("server-user")).thenReturn("carol");
		}
		return request;
	}

	private static String expectedRepositoryReference(String source) {
		return "urn:rdf4j:repository:" + UUID.nameUUIDFromBytes(source.getBytes(StandardCharsets.UTF_8));
	}

	private static RepositoryResult<Namespace> emptyNamespaces() {
		return new RepositoryResult<>(new CloseableIteratorIteration<>(List.<Namespace>of().iterator()));
	}

	private static void verifyDownloadEncoding(SailRepository repository, String acceptEncoding, boolean gzipped)
			throws Exception {
		CookieAwareQueryServlet servlet = new CookieAwareQueryServlet();
		WorkbenchRequest request = mock(WorkbenchRequest.class);
		HttpServletResponse response = mock(HttpServletResponse.class);

		when(request.getParameter("action")).thenReturn("exec");
		when(request.isParameterPresent("Accept")).thenReturn(true);
		when(request.getParameter("Accept")).thenReturn("text/csv");
		when(request.getHeader("Accept")).thenReturn("application/sparql-results+xml");
		when(request.getHeader("Accept-Encoding")).thenReturn(acceptEncoding);
		when(request.isParameterPresent(QueryServlet.QUERY)).thenReturn(false);
		when(response.getOutputStream()).thenReturn(new ByteArrayServletOutputStream());
		servlet.setRepository(repository);
		servlet.writeQueryCookie = true;
		servlet.setCookieHandler(mock(CookieHandler.class));

		servlet.service(request, response, "/transform");

		if (gzipped) {
			verify(response).setHeader("Content-Encoding", "gzip");
		} else {
			verify(response, never()).setHeader("Content-Encoding", "gzip");
		}
	}

	private static final class RecordingQueryServlet extends QueryServlet {
		private String lastDispatch;
		private Boolean lastWriteQueryCookie;
		private String lastXslPath;

		@Override
		protected void service(WorkbenchRequest req, HttpServletResponse resp, String xslPath) {
			lastDispatch = "GET";
			lastWriteQueryCookie = writeQueryCookie;
			lastXslPath = xslPath;
		}

		@Override
		protected void doPost(WorkbenchRequest req, HttpServletResponse resp, String xslPath) {
			lastDispatch = "POST";
			lastWriteQueryCookie = writeQueryCookie;
			lastXslPath = xslPath;
		}
	}

	private static final class CookieAwareQueryServlet extends QueryServlet {
		private void setCookieHandler(CookieHandler cookieHandler) {
			this.cookies = cookieHandler;
		}
	}

	private static final class ByteArrayServletOutputStream extends ServletOutputStream {
		private final ByteArrayOutputStream delegate = new ByteArrayOutputStream();

		@Override
		public void write(int b) {
			delegate.write(b);
		}

		@Override
		public boolean isReady() {
			return true;
		}

		@Override
		public void setWriteListener(WriteListener writeListener) {
			// not needed for unit tests
		}

		private String asString() {
			return delegate.toString(StandardCharsets.UTF_8);
		}
	}
